							// 使用Fisher-Yates算法部分洗牌（只需洗前count个）
							while (i-- > Math.max(0, arr.length - count)) {
								randomIndex = Math.floor(Math.random() * (i + 1));
								// 交换元素
								temp = shuffled[randomIndex];
								shuffled[randomIndex] = shuffled[i];
								shuffled[i] = temp;
							}
							return shuffled.slice(-count); // 返回洗牌后的最后count个元素
