						var name2;
						var list = ['liuxinghuoyu', 'dongzhuxianji'];
						var map = {
							dongzhuxianji: 'spade',
							liuxinghuoyu: 'heart'
						}
						for (var i = 0; i < list.length; i++) {
							var name = list[i];
							if (player.countCards('he', function (card) {
								return (get.value(card) < 5) && get.suit(card, player) == map[name];
							}) > 0) {
								if (temp > max) {
									max = temp;
									name2 = map[name];
								}

							}
						}
						if (name2 == get.suit(card, player)) return (name2 == 'spade' ? (5 - get.value(card)) : 20 - get.value(card));
