					hiddenCard(player, name) {

						if (get.type(name) == 'food') {
							return true;
						}
					},
					dialog(event, player) {
						'step 0'
						var list = [];
						for (var i in lib.card) {
							if (lib.card[i].mode && lib.card[i].mode.contains(lib.config.mode) == false) continue;
							if (lib.card[i].forbid && lib.card[i].forbid.contains(lib.config.mode)) continue;
							var name = lib.card[i];

							if (player.getHistory('useCard').length == 0 && lib.card[i].subtype == 'spell_bronze' && event.filterCard({
								name: i
							}, player, event)) {
								list.add(i);
							}
							if (player.getHistory('useCard').length == 1 && lib.card[i].subtype == 'spell_silver' && event.filterCard({
								name: i
							}, player, event)) {
								list.add(i);
							}
							if (player.getHistory('useCard').length == 2 && lib.card[i].subtype == 'spell_gold' && event.filterCard({
								name: i
							}, player, event)) {
								list.add(i);
							}


						}
						'step 1'
						return ui.create.dialog('奥秘', [list, 'vcard'], 'hidden')
					},
					filter(button, player) {
						return _status.event.getParent().filterCard({
							name: button.link[2]
						}, player, _status.event.getParent());
					},
					check(button) {
						if (button.link[2] == 'shan') return 3;
						var player = _status.event.player;
						if (button.link[2] == 'jiu') {
							if (player.getUseValue({
								name: 'jiu'
							}) <= 0) return 0;
							if (player.countCards('h', 'sha')) return player.getUseValue({
								name: 'jiu'
							});
						}
						return player.getUseValue({
							name: button.link[2]
						});
					},
